    req.Header.SetMethod(fasthttp.MethodGet)

    // Set timeout to 3 seconds
    timeout := 3 * time.Second
    // Note: fasthttp.Client.DoRedirects handles redirects internally.
    // We use a custom timeout mechanism via the client's ReadTimeout/WriteTimeout or context.
    // However, standard fasthttp.Client.DoRedirects does not accept a context directly in older versions.
    // To strictly enforce a 3-second timeout for the entire operation (including redirects),
    // we can use a channel with a timer or rely on client settings.
    // Here, we set the client's ReadTimeout and WriteTimeout.
    client.ReadTimeout = timeout
    client.WriteTimeout = timeout
    // client.MaxIdempotentRequestAttempts = 1 // Prevent retries for simplicity - Removed as field doesn't exist

    // Fetch the URL using DoRedirects (maxRedirects set to 10)
    maxRedirects := 10
    err := client.DoRedirects(req, resp, maxRedirects)

    if err != nil {
        ctx.SetStatusCode(fasthttp.StatusOK) // Return 200 OK with error in body as per typical API design
        respData := URLPreviewResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)}
        json.NewEncoder(ctx).Encode(respData)
