    description := extractMetaDescription(htmlBody)

    // Send successful response
    ctx.SetStatusCode(fasthttp.StatusOK)
    response := URLPreviewResponse{
        Title:       title,
        Description: description,
    }
    json.NewEncoder(ctx).Encode(response)
}

// extractTitle looks for <title> tag in the HTML
func extractTitle(html []byte) string {
    startTag := []byte("<title>")
    endTag := []byte("</title>")
    startIdx := bytes.Index(html, startTag)
    if startIdx == -1 {
        return ""
    }
    startIdx += len(startTag)
    endIdx := bytes.Index(html[startIdx:], endTag)
    if endIdx == -1 {
        return ""
    }
    return string(bytes.TrimSpace(html[startIdx : startIdx+endIdx]))
}

// extractMetaDescription looks for <meta name="description" content="...">
func extractMetaDescription(html []byte) string {
    // We look for patterns like: <meta name="description" content="...">
    // or <meta content="..." name="description">
    searchStr := []byte("name=\"description\"")
    idx := bytes.Index(html, searchStr)
    if idx == -1 {
        // Try single quotes
        searchStr = []byte("name='description'")
        idx = bytes.Index(html, searchStr)
        if idx == -1 {
            return ""
        }
    }

    // Look for content attribute within a reasonable window around the match
    // We scan backwards to find the start of the tag and forwards to find the end
    tagStart := bytes.LastIndexByte(html[:idx], '<')
    if tagStart == -1 {
        return ""
    }
    tagEnd := bytes.IndexByte(html[idx:], '>')
    if tagEnd == -1 {
        return ""
    }
    tagEnd += idx

    metaTag := html[tagStart:tagEnd]

    // Extract content attribute
    contentPrefix := []byte("content=\"")
    contentIdx := bytes.Index(metaTag, contentPrefix)
    if contentIdx == -1 {
        contentPrefix = []byte("content='")
        contentIdx = bytes.Index(metaTag, contentPrefix)
        if contentIdx == -1 {
            return ""
        }
    }
    contentIdx += len(contentPrefix)
    contentEnd := bytes.IndexByte(metaTag[contentIdx:], '"')
    if contentEnd == -1 {
        contentEnd = bytes.IndexByte(metaTag[contentIdx:], '\'')
        if contentEnd == -1 {
            return ""
        }
    }
    return string(bytes.TrimSpace(metaTag[contentIdx : contentIdx+contentEnd]))
}

