					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDesc && content != "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description, nil
}

func main() {
	// Register the handler
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

