	// Create a new router
	router := func(ctx *fasthttp.RequestCtx) {
		if string(ctx.Path()) == "/preview" {
			FetchURLPreview(ctx)
		} else {
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	// Start the server
	if err := fasthttp.ListenAndServe(":8080", router); err != nil {
		panic(err)
	}
}

