    }

    // Prepare request
    reqCtx := fasthttp.AcquireRequest()
    respCtx := fasthttp.AcquireResponse()
    defer fasthttp.ReleaseRequest(reqCtx)
    defer fasthttp.ReleaseResponse(respCtx)

    reqCtx.SetRequestURI(req.URL)
    reqCtx.Header.SetMethod("GET")
    reqCtx.Header.Set("User-Agent", "Go-FetchURLPreview/1.0")

    // Use DoRedirects to handle redirects
    err = client.DoRedirects(reqCtx, respCtx, 10)
    if err != nil {
        ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
        return
    }

    // 3. Parse HTML to extract Title and Meta Description
    body := respCtx.Body()
    title, description := parseHTML(body)

    // 4. Return JSON response
    response := URLPreviewResponse{
        Title:       title,
        Description: description,
    }

    ctx.SetContentType("application/json")
    json.NewEncoder(ctx).Encode(response)
}

// parseHTML walks the HTML tree to find the <title> and <meta name="description">
func parseHTML(body []byte) (string, string) {
    doc, err := html.Parse(bytes.NewReader(body))
    if err != nil {
        return "", ""
    }

    var title, description string
    var f func(*html.Node)

    f = func(n *html.Node) {
        if n.Type == html.ElementNode {
            // Extract Title
            if n.Data == "title" {
                if n.FirstChild != nil {
                    title = n.FirstChild.Data
                }
            }

            // Extract Meta Description
            if n.Data == "meta" {
                isDesc := false
                content := ""
                for _, attr := range n.Attr {
                    if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
                        isDesc = true
                    }
                    if attr.Key == "content" {
                        content = attr.Val
                    }
                }
                if isDesc && content != "" {
                    description = content
                }
            }
        }

        // Traverse children
        for c := n.FirstChild; c != nil; c = c.NextSibling {
            f(c)
        }
    }

    f(doc)
    return title, description
}

