    // We set maxRedirects to 10 (standard limit)
    // Note: The original code attempted to pass a boolean argument which is incorrect for this version of fasthttp.

    done := make(chan error, 1)
    go func() {
        done <- client.DoRedirects(req, resp, 10)
    }()

    select {
    case err := <-done:
        if err != nil {
            ctx.SetStatusCode(fasthttp.StatusBadGateway)
            ctx.SetContentType("application/json")
            json.NewEncoder(ctx).Encode(ResponseBody{Error: fmt.Sprintf("Failed to fetch URL: %v", err)})
