// parseHTML uses golang.org/x/net/html to parse the HTML content
func parseHTML(body []byte) (title string, description string) {
    doc, err := html.Parse(bytes.NewReader(body))
    if err != nil {
        return "", ""
    }

    var traverse func(*html.Node)
    traverse = func(n *html.Node) {
        if n.Type == html.ElementNode {
            switch n.Data {
            case "title":
                if n.FirstChild != nil {
                    title = n.FirstChild.Data
                }
            case "meta":
                isDesc := false
                content := ""
                for _, attr := range n.Attr {
                    if attr.Key == "name" && attr.Val == "description" {
                        isDesc = true
                    }
                    if attr.Key == "property" && attr.Val == "og:description" {
                        isDesc = true
                    }
                    if attr.Key == "content" {
                        content = attr.Val
                    }
